VALUES
  ('judicial-57112235-moex-00627', 'judicial-57112235', 'judicial-57112235-moex-111-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '累犯成年受刑人依現行相關法令之規定，其假釋要件下列敘述何者錯誤？', '["有悛悔實據者，有期徒刑執行逾三分之二", "累進處遇進至第二級受刑人已適於社會生活，而合於法定假釋之規定者", "最近2個月內教化、作業、操行各項分數，均應在3分以上", "有悛悔實據者，無期徒刑逾25年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "95b9205e8544", "answer_pdf_sha1": "6055fa1f5814", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00628', 'judicial-57112235', 'judicial-57112235-moex-111-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依監獄行刑法及行刑累進處遇條例之教化規定，下列敘述何者錯誤？', '["監獄得依受刑人請求安排適當之宗教師，實施教誨", "第二級以上之受刑人得為集會。但第二級每月以2次，第一級每月以4次為限", "第三級以上之受刑人，得聽收音機及留聲機", "第一級之受刑人，許其在圖書室閱覽圖書"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "95b9205e8544", "answer_pdf_sha1": "6055fa1f5814", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00629', 'judicial-57112235', 'judicial-57112235-moex-111-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '受刑人如有自費延醫需求時，得依監獄行刑法規定提出申請，有關監獄依相關矯正法令辦理受刑人自 費延醫之相關規定，下列敘述何者錯誤？', '["受刑人請求自費於監獄內延醫診治者，應以書面為之", "醫師開立相關證明應秉持醫療專業依診斷結果記載，不可配合加註受刑人建議之文字", "必要時，在不妨害機關安全及秩序之情形下，得准許醫師攜入醫療設備", "自費延醫所需之費用，以由受刑人之保管金或勞作金中扣繳支付為原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "95b9205e8544", "answer_pdf_sha1": "6055fa1f5814", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00630', 'judicial-57112235', 'judicial-57112235-moex-111-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '受刑人執行期間之收容方式須有所區別，有關下列4位受刑人之收容方式，何者錯誤？', '["受刑人甲：未滿18歲，應收容於少年矯正學校", "受刑人乙：監獄因其罹病需長期療養而給予和緩處遇，並與其他受刑人分別監禁", "受刑人丙：假釋後接續執行拘役，應與處徒刑者分別監禁", "受刑人丁：受移入違規舍之懲罰，而應與其他受刑人分別監禁"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "95b9205e8544", "answer_pdf_sha1": "6055fa1f5814", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00631', 'judicial-57112235', 'judicial-57112235-moex-111-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '少年矯正學校學生入校後，應作成個案分析報告，有關製作該報告之相關規定，下列敘述何者錯誤？', '["個案分析報告應依據心理學、教育學、社會學及醫學判斷", "應由教務處根據各有關處、室提供之調查資料，作成個案分析報告", "一般教學部者，應於1個月內完成後，提報學生處遇審查委員會決定分班、分級施教方法", "特別教學部者，應於15日內完成後，提報學生處遇審查委員會決定分班、分級施教方法"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "95b9205e8544", "answer_pdf_sha1": "6055fa1f5814", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00632', 'judicial-57112235', 'judicial-57112235-moex-111-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '監獄接獲依監獄行刑法第120條第1項假釋出監受刑人因刑期變更之相關執行指揮書，辦理重新核算 假釋，如新併入之刑期有同法第115條第2項不得報請假釋之情形者，應報由法務部如何處理？', '["不予許可假釋", "撤銷原假釋", "重核原假釋", "廢止原假釋"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "95b9205e8544", "answer_pdf_sha1": "6055fa1f5814", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00633', 'judicial-57112235', 'judicial-57112235-moex-111-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '機關得許可受刑人使用電話或其他通訊方式接見之情形，除機關基於人道考量，或認有助於機關管理 之必要外，下列敘述何者錯誤？', '["收容人之家屬或最近親屬喪亡或有生命危險", "收容人之家屬或最近親屬最近2個月，均未與其接見及通信", "收容人之配偶或直系血親另收容於矯正機關", "收容人請求與所屬國或地區之外交、領事人員或可代表其國家或地區之人員接見"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "95b9205e8544", "answer_pdf_sha1": "6055fa1f5814", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00634', 'judicial-57112235', 'judicial-57112235-moex-111-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關監獄對受刑人所為之處分應以電話、視訊或其他適當方式通知其家屬或最近親屬，下列敘述何 者錯誤？', '["施以隔離保護", "施以戒具懲罰", "施以固定保護", "收容於保護室"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "95b9205e8544", "answer_pdf_sha1": "6055fa1f5814", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00635', 'judicial-57112235', 'judicial-57112235-moex-111-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關外役監受刑人返家探視期間，下列敘述何者正確？', '["受刑人返家探視期間，每次最多不得超過40小時。但例假日或紀念日有連續3日以上時，得延長24 小時", "受刑人返家探視期間，每次為48小時。但例假日或紀念日有連續3日以上時，得延長36小時", "農曆春節放假5日，返家探視期間得延長48小時", "返家探視期間包括在途期間"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "95b9205e8544", "answer_pdf_sha1": "6055fa1f5814", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00636', 'judicial-57112235', 'judicial-57112235-moex-111-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '下列何者非外界對受刑人及被告送入金錢與飲食及必需物品辦法所稱之外界送入金錢？', '["新臺幣", "個人開立之支票", "中華郵政股份有限公司所簽發之匯票", "國內其他金融機構簽發之本票"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "95b9205e8544", "answer_pdf_sha1": "6055fa1f5814", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL)
